// Sample logic for parsing index.json and applying configurations
void LoadIndexJsonConfig() {
    cJSON* json = cJSON_Parse(index_json_content);
    if (!json) {
        ESP_LOGE(TAG, "Error parsing index.json");
        return;
    }

    cJSON* version = cJSON_GetObjectItem(json, "version");
    if (version && version->valuestring) {
        ESP_LOGI(TAG, "Loading assets version: %s", version->valuestring);
    }

    cJSON* models = cJSON_GetObjectItem(json, "models");
    if (models && cJSON_IsArray(models)) {
        int model_count = cJSON_GetArraySize(models);
        for (int i = 0; i < model_count; i++) {
            cJSON* model = cJSON_GetArrayItem(models, i);
            const char* model_path = cJSON_GetStringValue(model);
            if (model_path) {
                LoadSpeechRecognitionModel(model_path);
            }
        }
    }

    cJSON* themes = cJSON_GetObjectItem(json, "themes");
    if (themes && cJSON_IsArray(themes)) {
        int theme_count = cJSON_GetArraySize(themes);
        for (int i = 0; i < theme_count; i++) {
            cJSON* theme = cJSON_GetArrayItem(themes, i);
            const char* theme_name = cJSON_GetStringValue(theme);
            if (theme_name) {
                ApplyTheme(theme_name);
            }
        }
    }

    cJSON_Delete(json);
}
```

