bool Assets::Apply() {
    // Ensure partition is valid before proceeding
    if (!partition_valid_ || !checksum_valid_) {
        ESP_LOGE(TAG, "Cannot apply assets: Partition or checksum invalid.");
        return false;
    }

    // Get index.json asset data
    void* config_data_ptr = nullptr;
    size_t config_size = 0;
    if (!GetAssetData("index.json", config_data_ptr, config_size)) {
        ESP_LOGE(TAG, "Failed to retrieve index.json from assets");
        return false;
    }

    // Null terminate the JSON string safely
    std::string json_content(static_cast<const char*>(config_data_ptr), config_size);

    // Parse the JSON content
    cJSON* root = cJSON_Parse(json_content.c_str());
    if (!root) {
        ESP_LOGE(TAG, "Error parsing index.json");
        return false;
    }

    bool success = true;

    // Optional: Log version info
    cJSON* version_item = cJSON_GetObjectItem(root, "version");
    if (version_item && cJSON_IsString(version_item)) {
        ESP_LOGI(TAG, "Applying assets version: %s", version_item->valuestring);
    }

    // Apply Themes
    cJSON* themes_array = cJSON_GetObjectItem(root, "themes");
    if (themes_array && cJSON_IsArray(themes_array)) {
        int count = cJSON_GetArraySize(themes_array);
        for (int i = 0; i < count; ++i) {
            cJSON* theme_item = cJSON_GetArrayItem(themes_array, i);
            if (cJSON_IsString(theme_item)) {
                ApplyTheme(std::string(theme_item->valuestring));
            }
        }
    }

    // Load Speech Recognition Models
    cJSON* models_array = cJSON_GetObjectItem(root, "models");
    if (models_array && cJSON_IsArray(models_array)) {
        int count = cJSON_GetArraySize(models_array);
        for (int i = 0; i < count; ++i) {
            cJSON* model_item = cJSON_GetArrayItem(models_array, i);
            if (cJSON_IsString(model_item)) {
                LoadSpeechRecognitionModel(std::string(model_item->valuestring));
            }
        }
    }

    // Cleanup
    cJSON_Delete(root);

    if (!success) {
        Alert(Lang::Strings::ERROR, Lang::Strings::DOWNLOAD_ASSETS_FAILED, "circle_xmark", Lang::Sounds::OGG_EXCLAMATION);
        vTaskDelay(pdMS_TO_TICKS(2000));
        SetDeviceState(kDeviceStateActivating);
    }

    return success;
}

