esp_err_t Ota::CheckVersion() {
    // Retrieve current firmware version
    std::string current_version = Board::GetInstance().GetFirmwareVersion();
    if (current_version.empty()) {
        ESP_LOGE(TAG, "Failed to retrieve current firmware version");
        return ESP_FAIL;
    }

    // Construct URL for version checking endpoint
    std::string base_url = GetCheckVersionUrl();
    if (base_url.empty()) {
        ESP_LOGE(TAG, "OTA URL not configured");
        return ESP_ERR_INVALID_STATE;
    }

    // Append query parameters including current version and device model
    std::string device_model = Board::GetInstance().GetModelName();
    std::string firmware_url = base_url + "?version=" + current_version + "&model=" + device_model;

    // Setup HTTP client and perform GET request
    auto network = Board::GetInstance().GetNetwork();
    auto http = network->CreateHttp(0);
    if (!http->Open("GET", firmware_url)) {
        ESP_LOGE(TAG, "Failed to open HTTP connection to %s", firmware_url.c_str());
        return ESP_ERR_HTTP_CONNECT;
    }

    // Send request and wait for response
    int status_code = http->Send();
    if (status_code != 200) {
        ESP_LOGE(TAG, "Received non-success status code: %d", status_code);
        http->Close();
        return ESP_ERR_HTTP_ESTATUS;
    }

    // Read and parse JSON response
    std::string response_body = http->GetString();
    http->Close();

    cJSON* json = cJSON_Parse(response_body.c_str());
    if (!json) {
        ESP_LOGE(TAG, "Failed to parse JSON response");
        return ESP_ERR_INVALID_JSON;
    }

    const cJSON* new_version_item = cJSON_GetObjectItemCaseSensitive(json, "version");
    if (!cJSON_IsString(new_version_item)) {
        ESP_LOGE(TAG, "Invalid or missing 'version' field in response");
        cJSON_Delete(json);
        return ESP_ERR_NOT_FOUND;
    }

    std::string new_version = new_version_item->valuestring;

    // Compare current vs remote version
    bool is_new_available = IsNewVersionAvailable(current_version, new_version);
    if (is_new_available) {
        ESP_LOGI(TAG, "New firmware version available: %s", new_version.c_str());
        // Optionally store new version info or initiate download here
    } else {
        ESP_LOGI(TAG, "Device is up to date.");
    }

    cJSON_Delete(json);
    return ESP_OK;
}

