bool Ota::Upgrade(const std::string& firmware_url, std::function<void(int progress, size_t speed)> callback) {
    const char* TAG = "OTA";

    // Step 1: Establish HTTP connection
    auto network = Board::GetInstance().GetNetwork();
    auto http = network->CreateHttp(0);
    if (!http->Open("GET", firmware_url)) {
        ESP_LOGE(TAG, "Failed to open HTTP connection");
        return false;
    }

    if (http->GetStatusCode() != 200) {
        ESP_LOGE(TAG, "Failed to get firmware, status code: %d", http->GetStatusCode());
        http->Close();
        return false;
    }

    size_t content_length = http->GetBodyLength();
    if (content_length == 0) {
        ESP_LOGE(TAG, "Failed to get content length");
        http->Close();
        return false;
    }

    // Step 2: Prepare OTA partition
    esp_ota_handle_t update_handle = 0;
    const esp_partition_t* update_partition = esp_ota_get_next_update_partition(NULL);
    if (update_partition == nullptr) {
        ESP_LOGE(TAG, "Failed to get update partition");
        http->Close();
        return false;
    }

    ESP_LOGI(TAG, "Writing to partition %s at offset 0x%lx", update_partition->label, update_partition->address);

    esp_err_t err = esp_ota_begin(update_partition, OTA_WITH_SEQUENTIAL_WRITES, &update_handle);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to begin OTA: %s", esp_err_to_name(err));
        http->Close();
        return false;
    }

    // Step 3: Download and flash firmware
    char buffer[512];
    size_t total_read = 0, recent_read = 0;
    int64_t last_calc_time = esp_timer_get_time();
    bool image_header_checked = false;
    std::string image_header;

    while (true) {
        int ret = http->Read(buffer, sizeof(buffer));
        if (ret < 0) {
            ESP_LOGE(TAG, "Failed to read HTTP data: %s", esp_err_to_name(ret));
            esp_ota_abort(update_handle);
            http->Close();
            return false;
        }

        // Accumulate header for validation
        if (!image_header_checked && ret > 0) {
            image_header.append(buffer, ret);
            if (image_header.size() >= sizeof(esp_image_header_t) + sizeof(esp_image_segment_header_t) + sizeof(esp_app_desc_t)) {
                esp_app_desc_t new_app_info;
                memcpy(&new_app_info,
                       image_header.data() + sizeof(esp_image_header_t) + sizeof(esp_image_segment_header_t),
                       sizeof(esp_app_desc_t));

                const esp_app_desc_t* current_app_info = esp_app_get_description();
                ESP_LOGI(TAG, "Current version: %s, New version: %s", current_app_info->version, new_app_info.version);

                image_header_checked = true;
                image_header.clear();  // Free memory
            }
        }

        // Write data to OTA partition
        if (ret > 0) {
            err = esp_ota_write(update_handle, buffer, ret);
            if (err != ESP_OK) {
                ESP_LOGE(TAG, "Failed to write OTA data: %s", esp_err_to_name(err));
                esp_ota_abort(update_handle);
                http->Close();
                return false;
            }

            recent_read += ret;
            total_read += ret;
        }

        // Report progress and speed
        int64_t now = esp_timer_get_time();
        if ((now - last_calc_time) >= 1000000 || ret == 0) {
            size_t progress = static_cast<size_t>(static_cast<float>(total_read) / content_length * 100);
            size_t speed_bps = recent_read;  // Since interval is ~1 sec
            ESP_LOGI(TAG, "Progress: %zu%% (%zu/%zu), Speed: %zu B/s", progress, total_read, content_length, speed_bps);
            if (callback) {
                callback(static_cast<int>(progress), speed_bps);
            }
            last_calc_time = now;
            recent_read = 0;
        }

        if (ret == 0) {
            break;  // Done reading
        }
    }

    // Step 4: Finalize OTA
    http->Close();

    err = esp_ota_end(update_handle);
    if (err != ESP_OK) {
        if (err == ESP_ERR_OTA_VALIDATE_FAILED) {
            ESP_LOGE(TAG, "Image validation failed, image is corrupted");
        } else {
            ESP_LOGE(TAG, "Failed to end OTA: %s", esp_err_to_name(err));
        }
        return false;
    }

    err = esp_ota_set_boot_partition(update_partition);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to set boot partition: %s", esp_err_to_name(err));
        return false;
    }

    ESP_LOGI(TAG, "Firmware upgrade successful");
    return true;
}

