bool AudioCodec::InputData(std::vector<int16_t>& audio_data) {
    // Step 1: Check if input device exists
    if (!input_dev_) {
        return false;
    }

    // Step 2: Enable input stream if not already done
    if (!input_enabled_) {
        esp_err_t ret = esp_codec_dev_open(input_dev_);
        if (ret != ESP_OK) {
            return false;
        }
        input_enabled_ = true;
    }

    // Step 3: Determine how many samples to read based on desired buffer size
    size_t bytes_to_read = audio_data.size() * sizeof(int16_t);

    // Step 4: Read data from codec device
    size_t bytes_read = 0;
    esp_err_t ret = esp_codec_dev_read(input_dev_, audio_data.data(), bytes_to_read, &bytes_read);
    if (ret != ESP_OK || bytes_read == 0) {
        return false;
    }

    // Resize buffer according to actual bytes read
    audio_data.resize(bytes_read / sizeof(int16_t));

    // Step 5: Convert stereo to mono if necessary
    if (input_channels_ == 2) {
        std::vector<int16_t> mono_data(audio_data.size() / 2);
        for (size_t i = 0, j = 0; i < mono_data.size(); ++i, j += 2) {
            mono_data[i] = audio_data[j];  // Take left channel
        }
        audio_data = std::move(mono_data);
    }

    return true;
}

