void SetInputGain(float gain) {
    // Avoid unnecessary updates if the gain hasn't changed
    if (gain == input_gain_) {
        return;
    }

    // Ensure the device is valid before proceeding
    if (input_dev_ == nullptr) {
        ESP_LOGE(TAG, "Input device is null, cannot set gain");
        return;
    }

    // Apply the input gain to the codec device
    esp_err_t ret = esp_codec_dev_set_in_gain(input_dev_, gain);
    if (ret != ESP_OK) {
        ESP_LOGE(TAG, "Failed to set input gain to %.2f dB, err = %d", gain, ret);
        return;
    }

    // Log successful update
    ESP_LOGI(TAG, "Set input gain to %.2f dB", gain);

    // Update internal state
    input_gain_ = gain;
}

