void initialize_udp_socket(const char* server_ip, int port) {
#if CONFIG_USE_AUDIO_DEBUGGER
    udp_sockfd_ = socket(AF_INET, SOCK_DGRAM, IPPROTO_UDP);
    if (udp_sockfd_ < 0) {
        ESP_LOGE(TAG, "Failed to create UDP socket: %d", errno);
