    udp_server_addr_.sin_family = AF_INET;
    udp_server_addr_.sin_port = htons(port);
    if (inet_aton(server_ip, &udp_server_addr_.sin_addr) == 0) {
        ESP_LOGE(TAG, "Invalid server IP address: %s", server_ip);
        close(udp_sockfd_);
        udp_sockfd_ = -1;
        return;
