#include <cjson/cJSON.h>
#include <fstream>
#include <sstream>
#include <string>
#include <vector>
#include "esp_log.h"

void ParseWakenetModelConfig() {
    const char* TAG = "WakenetConfig";

    // Set defaults first
    language_ = "cn";
    duration_ = 3000;
    threshold_ = 0.2;

    // Build path to index.json
    std::string configPath = std::string(models_->model_path) + "/index.json";
    ESP_LOGD(TAG, "Loading config from: %s", configPath.c_str());

    // Open and read file into buffer
    std::ifstream file(configPath);
    if (!file.is_open()) {
        ESP_LOGE(TAG, "Failed to open config file: %s", configPath.c_str());
        return;
    }

    std::stringstream buffer;
    buffer << file.rdbuf();
    std::string content = buffer.str();
    file.close();

    // Parse JSON
    cJSON* root = cJSON_Parse(content.c_str());
    if (root == nullptr) {
        ESP_LOGE(TAG, "Failed to parse JSON content");
        const char* error_ptr = cJSON_GetErrorPtr();
        if (error_ptr != NULL) {
            ESP_LOGE(TAG, "Error before: %s", error_ptr);
        }
        return;
    }

    // Parse language
    cJSON* langItem = cJSON_GetObjectItemCaseSensitive(root, "language");
    if (langItem && cJSON_IsString(langItem)) {
        language_ = langItem->valuestring;
    } else {
        ESP_LOGW(TAG, "Using default language: %s", language_.c_str());
    }

    // Parse duration
    cJSON* durItem = cJSON_GetObjectItemCaseSensitive(root, "duration");
    if (durItem && cJSON_IsNumber(durItem)) {
        duration_ = static_cast<int>(durItem->valuedouble);
    } else {
        ESP_LOGW(TAG, "Using default duration: %d ms", duration_);
    }

    // Parse threshold
    cJSON* threshItem = cJSON_GetObjectItemCaseSensitive(root, "threshold");
    if (threshItem && cJSON_IsNumber(threshItem)) {
        threshold_ = static_cast<float>(threshItem->valuedouble);
    } else {
        ESP_LOGW(TAG, "Using default threshold: %.2f", threshold_);
    }

    // Parse commands array
    cJSON* cmdsArray = cJSON_GetObjectItemCaseSensitive(root, "commands");
    if (cmdsArray && cJSON_IsArray(cmdsArray)) {
        commands_.clear();
        int size = cJSON_GetArraySize(cmdsArray);
        for (int i = 0; i < size; ++i) {
            cJSON* cmdObj = cJSON_GetArrayItem(cmdsArray, i);
            if (!cmdObj) continue;

            cJSON* wakeWordItem = cJSON_GetObjectItemCaseSensitive(cmdObj, "wake_word");
            cJSON* displayNameItem = cJSON_GetObjectItemCaseSensitive(cmdObj, "display_name");
            cJSON* typeItem = cJSON_GetObjectItemCaseSensitive(cmdObj, "type");

            if (cJSON_IsString(wakeWordItem) &&
                cJSON_IsString(displayNameItem) &&
                cJSON_IsString(typeItem)) {

                Command cmd;
                cmd.wake_word = wakeWordItem->valuestring;
                cmd.display_name = displayNameItem->valuestring;
                cmd.type = typeItem->valuestring;
                commands_.push_back(std::move(cmd));
            } else {
                ESP_LOGW(TAG, "Skipping malformed command entry at index %d", i);
            }
        }
    } else {
        ESP_LOGW(TAG, "No valid 'commands' array found in config.");
    }

    // Log parsed commands
    for (const auto& cmd : commands_) {
        ESP_LOGD(TAG, "Parsed Command - Wake Word: %s, Display Name: %s, Type: %s",
                 cmd.wake_word.c_str(), cmd.display_name.c_str(), cmd.type.c_str());
    }

    // Cleanup
    cJSON_Delete(root);
}

