void AfeWakeWord::EncodeWakeWordData() {
    constexpr size_t stack_size = 4096;

    // Allocate memory for task stack and TCB buffer
    wake_word_encode_task_stack_ = static_cast<StackType_t*>(malloc(sizeof(StackType_t) * stack_size));
    wake_word_encode_task_buffer_ = static_cast<StaticTask_t*>(malloc(sizeof(StaticTask_t)));

    if (!wake_word_encode_task_stack_ || !wake_word_encode_task_buffer_) {
        ESP_LOGE(TAG, "Failed to allocate memory for wake word encode task");
        return;
    }

    // Create and launch static task for encoding
    wake_word_encode_task_ = xTaskCreateStatic([](void* arg) {
        auto this_ = (AfeWakeWord*)arg;
        {
            auto start_time = esp_timer_get_time();

            // Initialize Opus encoder with low complexity for speed
            auto encoder = std::make_unique<OpusEncoderWrapper>(16000, 1, OPUS_FRAME_DURATION_MS);
            encoder->SetComplexity(0); // 0 is the fastest

            int packets = 0;
            for (auto& pcm : this_->wake_word_pcm_) {
                encoder->Encode(std::move(pcm), [this_](std::vector<uint8_t>&& opus) {
                    std::lock_guard<std::mutex> lock(this_->wake_word_mutex_);
                    this_->wake_word_opus_.emplace_back(std::move(opus));
                    this_->wake_word_cv_.notify_all();
                });
                packets++;
            }

            // Clear PCM data after encoding
            this_->wake_word_pcm_.clear();

            auto end_time = esp_timer_get_time();
            ESP_LOGI(TAG, "Encoded wake word: %d packets in %ld ms", packets, (long)((end_time - start_time) / 1000));

            // Add termination marker
            std::lock_guard<std::mutex> lock(this_->wake_word_mutex_);
            this_->wake_word_opus_.push_back(std::vector<uint8_t>());
            this_->wake_word_cv_.notify_all();
        }

        vTaskDelete(NULL);
    }, "encode_wake_word", stack_size, this, 2, wake_word_encode_task_stack_, wake_word_encode_task_buffer_);

    if (!wake_word_encode_task_) {
        ESP_LOGE(TAG, "Failed to create wake word encode task");
        free(wake_word_encode_task_stack_);
        free(wake_word_encode_task_buffer_);
        wake_word_encode_task_stack_ = nullptr;
        wake_word_encode_task_buffer_ = nullptr;
    }
}

