void ReceiveWifiCredentialsFromAudio(Application* app, WifiManager* wifi_manager, Display* display, size_t target_sample_rate) {
    constexpr const char* kLogTag = "AudioCredReceiver";

    // Initialize signal processor for AFSK (mark=1200Hz, space=2200Hz)
    AudioSignalProcessor signal_processor(1200, 2200, target_sample_rate);

    while (true) {
        if (app->GetDeviceState() != kDeviceStateWifiConfiguring) {
            vTaskDelay(pdMS_TO_TICKS(100));
            continue;
        }

        std::vector<int16_t> audio_data;
        if (!app->GetAudioService().ReadAudioData(audio_data, target_sample_rate, 480)) {
            ESP_LOGI(kLogTag, "Failed to read audio data, retrying.");
            vTaskDelay(pdMS_TO_TICKS(10));
            continue;
        }

        // Stereo to mono conversion if necessary
        if (app->GetAudioService().GetChannelCount() == 2) {
            auto mono_data = std::vector<int16_t>(audio_data.size() / 2);
            for (size_t i = 0, j = 0; i < mono_data.size(); ++i, j += 2) {
                mono_data[i] = audio_data[j];
            }
            audio_data = std::move(mono_data);
        }

        // Simple downsampling based on step ratio
        const float input_rate = static_cast<float>(app->GetAudioService().GetSampleRate());
        const float kDownsampleStep = input_rate / static_cast<float>(target_sample_rate);
        std::vector<float> downsampled_data;
        size_t last_index = 0;

        if (kDownsampleStep > 1.0f) {
            downsampled_data.reserve(audio_data.size() / static_cast<size_t>(kDownsampleStep));
            for (size_t i = 0; i < audio_data.size(); ++i) {
                size_t sample_index = static_cast<size_t>(i / kDownsampleStep);
                if ((sample_index + 1) > last_index) {
                    downsampled_data.push_back(static_cast<float>(audio_data[i]));
                    last_index = sample_index + 1;
                }
            }
        } else {
            downsampled_data.reserve(audio_data.size());
            for (int16_t sample : audio_data) {
                downsampled_data.push_back(static_cast<float>(sample));
            }
        }

        // Feed samples into signal processor
        signal_processor.FeedSamples(downsampled_data);

        // Attempt to decode received string
        struct {
            std::unique_ptr<std::string> decoded_text;
        } data_buffer;

        if (signal_processor.TryDecodeString(data_buffer.decoded_text)) {
            if (!data_buffer.decoded_text || data_buffer.decoded_text->empty()) {
                ESP_LOGW(kLogTag, "Decoded empty or null text");
                continue;
            }

            // Parse SSID and password
            std::string wifi_ssid, wifi_password;
            size_t newline_position = data_buffer.decoded_text->find('\n');
            if (newline_position != std::string::npos) {
                wifi_ssid = data_buffer.decoded_text->substr(0, newline_position);
                wifi_password = data_buffer.decoded_text->substr(newline_position + 1);
            } else {
                ESP_LOGE(kLogTag, "Invalid data format, no newline character found");
                continue;
            }

            // Save credentials and exit config mode
            auto& ssid_manager = SsidManager::GetInstance();
            ssid_manager.AddSsid(wifi_ssid, wifi_password);

            wifi_manager->StopConfigAp();
            data_buffer.decoded_text.reset();

            return;
        }
    }
}

