float FrequencyDetector::GetAmplitude() const {
    if (state_buffer_.size() < 2) {
        return 0.0f;
    }

    float s_minus_1 = state_buffer_[0];
    float s_current = state_buffer_[1];

    // Compute amplitude: sqrt(S[N]^2 + S[N-1]^2 - S[N]*S[N-1]*coeff)
    return std::sqrt(s_current * s_current + s_minus_1 * s_minus_1 - filter_coefficient_ * s_current * s_minus_1);
}
```

