    // Try reading existing UUID from NVS
    size_t required_size = 0;
    err = nvs_get_str(nvs_handle, uuid_key, nullptr, &required_size);
    if (err == ESP_OK && required_size > 0) {
        uuid_.resize(required_size);
        err = nvs_get_str(nvs_handle, uuid_key, uuid_.data(), &required_size);
