    uuid_ = GenerateUuid();

    // Save newly generated UUID to NVS
    err = nvs_set_str(nvs_handle, uuid_key, uuid_.c_str());
    if (err == ESP_OK) {
        nvs_commit(nvs_handle);  // Commit changes to NVS
    }

