void WifiBoard::StartNetwork() {
    auto& wifi_manager = WifiManager::GetInstance();
    auto display = Board::GetInstance().GetDisplay();

    // Initialize WiFi manager with SSID prefix and locale
    wifi_manager.Initialize("MY_SSID_PREFIX", "en");

    // Set up event callback for handling WiFi events
    wifi_manager.SetEventCallback([this, display](WifiEvent event, const std::string& data) {
        switch (event) {
            case WifiEvent::Scanning:
                display->ShowNotification(Lang::Strings::SCANNING_WIFI, 30000);
                xEventGroupSetBits(event_group_, MAIN_EVENT_NETWORK_DISCONNECTED);
                break;

            case WifiEvent::Connecting:
                if (data.empty()) {
                    display->SetStatus(Lang::Strings::REGISTERING_NETWORK);
                } else {
                    std::string msg = Lang::Strings::CONNECT_TO;
                    msg += data;
                    msg += "...";
                    display->ShowNotification(msg.c_str(), 30000);
                }
                break;

            case WifiEvent::Connected: {
                std::string msg = Lang::Strings::CONNECTED_TO;
                msg += data;
                display->ShowNotification(msg.c_str(), 30000);
                xEventGroupSetBits(event_group_, MAIN_EVENT_NETWORK_CONNECTED);
                break;
            }

            case WifiEvent::Disconnected:
                xEventGroupSetBits(event_group_, MAIN_EVENT_NETWORK_DISCONNECTED);
                break;

            case WifiEvent::ConfigModeEnter:
                display->SetStatus(Lang::Strings::CONFIG_MODE_ENTER);
                #ifdef CONFIG_USE_HOTSPOT_WIFI_PROVISIONING
                    std::string hint = Lang::Strings::CONNECT_TO_HOTSPOT;
                    hint += wifi_manager.GetApSsid();
                    hint += Lang::Strings::ACCESS_VIA_BROWSER;
                    hint += wifi_manager.GetApWebUrl();
                    Application::GetInstance().Alert(
                        Lang::Strings::WIFI_CONFIG_MODE,
                        hint.c_str(),
                        "gear",
                        Lang::Sounds::OGG_WIFICONFIG
                    );
                #endif
                break;

            case WifiEvent::ConfigModeExit:
                display->SetStatus(Lang::Strings::CONFIG_MODE_EXIT);
                break;
        }
    });

    // Start connection attempt
    wifi_manager.StartConnection();

    // Schedule timeout check to fallback to config mode if needed
    Application::GetInstance().Schedule([this]() {
        EventBits_t bits = xEventGroupGetBits(event_group_);
        if ((bits & MAIN_EVENT_NETWORK_CONNECTED) == 0) {
            OnWifiConnectTimeout(this);
        }
    }, WIFI_CONNECTION_TIMEOUT_MS); // Assume defined elsewhere e.g., 30000 ms
}

