void Esp32Board::SetPowerSaveLevel(PowerSaveLevel level) {
  // Access WifiManager singleton
  auto &wifi_manager = WifiManager::GetInstance();

  // Ensure WifiManager is initialized before proceeding
  if (!wifi_manager.IsInitialized() && !wifi_manager.Initialize()) {
    ESP_LOGE(TAG, "Failed to initialize WifiManager");
    return;
  }

  // Check user-defined setting to see if sleep mode is allowed
  Settings settings("wifi", false);
  if (!settings.GetBool("sleep_mode", true)) {
    ESP_LOGI(TAG, "Power save timer is disabled by settings");
    wifi_manager.SetPowerSaveMode(WIFI_PS_NONE); // Force disable regardless of level
    return;
  }

  // Map PowerSaveLevel to ESP32-specific Wi-Fi power save modes
  wifi_ps_type_t ps_mode;
  switch (level) {
    case PowerSaveLevel::LOW_POWER:
      ps_mode = WIFI_PS_MAX_MODEM;
      break;
    case PowerSaveLevel::BALANCED:
      ps_mode = WIFI_PS_MIN_MODEM;
      break;
    case PowerSaveLevel::PERFORMANCE:
      ps_mode = WIFI_PS_NONE;
      break;
    default:
      ESP_LOGW(TAG, "Unknown PowerSaveLevel, defaulting to NONE");
      ps_mode = WIFI_PS_NONE;
      break;
  }

  // Apply selected power save mode
  esp_err_t err = wifi_manager.SetPowerSaveMode(ps_mode);
  if (err != ESP_OK) {
    ESP_LOGE(TAG, "Failed to set Wi-Fi power save mode: %s", esp_err_to_name(err));
  } else {
    ESP_LOGI(TAG, "Wi-Fi power save mode set to %d", ps_mode);
  }
}

