MqttProtocol::MqttProtocol(NetworkInterface* network) {
    // Step 1: Initialize the event group for synchronization
    event_group_handle_ = xEventGroupCreate();
    if (event_group_handle_ == nullptr) {
        ESP_LOGE(TAG, "Failed to create event group");
        return;
    }

    // Step 2: Initialize alive flag for task lifecycle control
    alive_ = std::make_shared<bool>(true);

    // Step 3: Configure and start the periodic reconnect timer
    esp_timer_create_args_t timer_config = {};
    timer_config.callback = &MqttProtocol::ReconnectTimerCallback;
    timer_config.arg = this;
    timer_config.name = "mqtt_reconnect_timer";

    esp_err_t err = esp_timer_create(&timer_config, &reconnect_timer_);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to create reconnect timer: %s", esp_err_to_name(err));
        return;
    }

    err = esp_timer_start_periodic(reconnect_timer_, RECONNECT_INTERVAL_USEC);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to start reconnect timer: %s", esp_err_to_name(err));
        return;
    }

    // Step 4: Initialize MQTT client via NetworkInterface
    mqtt_ = network->CreateMqtt(0);
    if (!mqtt_) {
        ESP_LOGE(TAG, "Failed to initialize MQTT client");
        return;
    }

    // Step 5: Log successful initialization
    ESP_LOGI(TAG, "MqttProtocol init");
}

MqttProtocol::~MqttProtocol() {
    // Mark the instance as inactive to prevent further processing in callbacks
    if (alive_) {
        *alive_ = false;
    }

    // Stop and delete the reconnect timer to prevent future triggers
    if (reconnect_timer_) {
        esp_timer_stop(reconnect_timer_);
        esp_timer_delete(reconnect_timer_);
        reconnect_timer_ = nullptr;
    }

    // Reset the MQTT client to cleanly disconnect and release its resources
    mqtt_.reset();

    // Delete the FreeRTOS event group used for synchronization
    if (event_group_handle_) {
        vEventGroupDelete(event_group_handle_);
        event_group_handle_ = nullptr;
    }
}

