bool MqttProtocol::StartMqttClient(bool force_reinit) {
    ESP_LOGI(TAG, "Starting MQTT client, force_reinit=%d", force_reinit);

    // Only initialize if not already done or forced
    if (mqtt_ == nullptr || force_reinit) {
        Settings settings("mqtt", false);
        std::string host = settings.GetString("host");
        int port = settings.GetInt("port");
        std::string username = settings.GetString("username");
        std::string password = settings.GetString("password");
        std::string client_id = settings.GetString("client_id");

        if (host.empty()) {
            ESP_LOGE(TAG, "MQTT host is empty");
            SetError(Lang::Strings::INVALID_CONFIGURATION);
            return false;
        }

        mqtt_.reset(); // Clean previous instance
        mqtt_ = network->CreateMqtt(client_id.empty() ? GenerateClientId().c_str() : client_id.c_str());

        if (!username.empty()) {
            mqtt_->SetCredentials(username.c_str(), password.c_str());
        }
        mqtt_->SetServer(host.c_str(), port);

        // Register event handlers
        mqtt_->OnConnected([this](bool session_present) {
            ESP_LOGI(TAG, "MQTT connected, session_present: %d", session_present);
            xEventGroupSetBits(event_group_handle_, MQTT_PROTOCOL_CONNECTED_EVENT);
        });

        mqtt_->OnDisconnected([this](int cause) {
            ESP_LOGI(TAG, "MQTT disconnected, cause: %d", cause);
            xEventGroupClearBits(event_group_handle_, MQTT_PROTOCOL_CONNECTED_EVENT);

            // Schedule reconnect attempt
            esp_timer_start_once(reconnect_timer_, MQTT_RECONNECT_INTERVAL_MS * 1000);
        });

        mqtt_->OnData([this](const char* topic, const char* data, int len) {
            HandleIncomingMessage(topic, data, len);
        });
    }

    // Attempt to connect
    if (!mqtt_->Connect()) {
        ESP_LOGE(TAG, "Failed to connect to MQTT server, code=%d", mqtt_->GetLastError());
        SetError(Lang::Strings::SERVER_NOT_CONNECTED);
        return false;
    }

    // Optionally wait for server hello (example use case)
    EventBits_t bits = xEventGroupWaitBits(
        event_group_handle_,
        MQTT_PROTOCOL_SERVER_HELLO_EVENT,
        pdTRUE,
        pdFALSE,
        pdMS_TO_TICKS(10000)
    );
    if (!(bits & MQTT_PROTOCOL_SERVER_HELLO_EVENT)) {
        ESP_LOGE(TAG, "Failed to receive server hello");
        SetError(Lang::Strings::SERVER_TIMEOUT);
        return false;
    }

    ESP_LOGI(TAG, "MQTT client started successfully");
    return true;
}

