bool MqttProtocol::ParseServerHello(const cJSON* root) {
    // Validate transport type
    auto transport = cJSON_GetObjectItem(root, "transport");
    if (transport == nullptr || !cJSON_IsString(transport) || strcmp(transport->valuestring, "udp") != 0) {
        ESP_LOGE(TAG, "Unsupported or missing transport: %s", transport ? transport->valuestring : "null");
        return false;
    }

    // Parse UDP configuration
    auto udp = cJSON_GetObjectItem(root, "udp");
    if (!cJSON_IsObject(udp)) {
        ESP_LOGE(TAG, "UDP configuration is missing or invalid");
        return false;
    }

    auto server_item = cJSON_GetObjectItem(udp, "server");
    auto port_item = cJSON_GetObjectItem(udp, "port");
    auto key_item = cJSON_GetObjectItem(udp, "key");
    auto nonce_item = cJSON_GetObjectItem(udp, "nonce");

    if (!cJSON_IsString(server_item) || !cJSON_IsNumber(port_item) ||
        !cJSON_IsString(key_item) || !cJSON_IsString(nonce_item)) {
        ESP_LOGE(TAG, "Missing or invalid UDP configuration fields");
        return false;
